207→// WriteSession writes a session to Claude's storage (JSONL transcript file).
208→// Uses the NativeData field which contains raw JSONL bytes.
209→// The session must have been created by Claude Code (AgentName check).
210→func (c *ClaudeCodeAgent) WriteSession(session *agent.AgentSession) error {
211→	if session == nil {
212→		return errors.New("session is nil")
213→	}
214→
215→	// Verify this session belongs to Claude Code
216→	if session.AgentName != "" && session.AgentName != c.Name() {
217→		return fmt.Errorf("session belongs to agent %q, not %q", session.AgentName, c.Name())
218→	}
219→
220→	if session.SessionRef == "" {
221→		return errors.New("session reference (transcript path) is required")
222→	}
223→
224→	if len(session.NativeData) == 0 {
225→		return errors.New("session has no native data to write")
226→	}
227→
228→	// Write the raw JSONL data
229→	if err := os.WriteFile(session.SessionRef, session.NativeData, 0o600); err != nil {
230→		return fmt.Errorf("failed to write transcript: %w", err)
231→	}
232→
233→	return nil
234→}
