258→// TruncateAtUUID returns a new session truncated at the given UUID (inclusive).
259→// This is used for rewind operations to restore transcript state.
260→// Requires NativeData to be populated.
261→func (c *ClaudeCodeAgent) TruncateAtUUID(session *agent.AgentSession, uuid string) (*agent.AgentSession, error) {
262→	if session == nil {
263→		return nil, errors.New("session is nil")
264→	}
265→
266→	if len(session.NativeData) == 0 {
267→		return nil, errors.New("session has no native data")
268→	}
269→
270→	if uuid == "" {
271→		// No truncation needed, return copy
272→		return &agent.AgentSession{
273→			SessionID:     session.SessionID,
274→			AgentName:     session.AgentName,
275→			RepoPath:      session.RepoPath,
276→			SessionRef:    session.SessionRef,
277→			StartTime:     session.StartTime,
278→			NativeData:    session.NativeData,
279→			ModifiedFiles: session.ModifiedFiles,
280→		}, nil
281→	}
282→
283→	// Parse, truncate, re-serialize
284→	lines, err := transcript.ParseFromBytes(session.NativeData)
285→	if err != nil {
286→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
287→	}
288→
289→	truncated := TruncateAtUUID(lines, uuid)
290→
291→	newData, err := SerializeTranscript(truncated)
292→	if err != nil {
293→		return nil, fmt.Errorf("failed to serialize truncated transcript: %w", err)
294→	}
295→
296→	return &agent.AgentSession{
297→		SessionID:     session.SessionID,
298→		AgentName:     session.AgentName,
299→		RepoPath:      session.RepoPath,
300→		SessionRef:    session.SessionRef,
301→		StartTime:     session.StartTime,
302→		NativeData:    newData,
303→		ModifiedFiles: ExtractModifiedFiles(truncated),
304→	}, nil
305→}
