 83→// ParseHookInput parses Gemini CLI hook input from stdin.
 84→func (g *GeminiCLIAgent) ParseHookInput(hookType agent.HookType, reader io.Reader) (*agent.HookInput, error) {
 85→	data, err := io.ReadAll(reader)
 86→	if err != nil {
 87→		return nil, fmt.Errorf("failed to read input: %w", err)
 88→	}
 89→
 90→	if len(data) == 0 {
 91→		return nil, errors.New("empty input")
 92→	}
 93→
 94→	input := &agent.HookInput{
 95→		HookType:  hookType,
 96→		Timestamp: time.Now(),
 97→		RawData:   make(map[string]interface{}),
 98→	}
 99→
100→	// Parse based on hook type
101→	switch hookType {
102→	case agent.HookSessionStart, agent.HookSessionEnd, agent.HookStop:
103→		var raw sessionInfoRaw
104→		if err := json.Unmarshal(data, &raw); err != nil {
105→			return nil, fmt.Errorf("failed to parse session info: %w", err)
106→		}
107→		input.SessionID = raw.SessionID
108→		input.SessionRef = raw.TranscriptPath
109→		// Store Gemini-specific fields in RawData
110→		input.RawData["cwd"] = raw.Cwd
111→		input.RawData["hook_event_name"] = raw.HookEventName
112→		if raw.Source != "" {
113→			input.RawData["source"] = raw.Source
114→		}
115→		if raw.Reason != "" {
116→			input.RawData["reason"] = raw.Reason
117→		}
118→
119→	case agent.HookUserPromptSubmit:
120→		// BeforeAgent is Gemini's equivalent to Claude's UserPromptSubmit
121→		// It provides the user's prompt in the "prompt" field
122→		var raw agentHookInputRaw
123→		if err := json.Unmarshal(data, &raw); err != nil {
124→			return nil, fmt.Errorf("failed to parse agent hook input: %w", err)
125→		}
126→		input.SessionID = raw.SessionID
127→		input.SessionRef = raw.TranscriptPath
128→		input.RawData["cwd"] = raw.Cwd
129→		input.RawData["hook_event_name"] = raw.HookEventName
130→		if raw.Prompt != "" {
131→			input.UserPrompt = raw.Prompt
132→			input.RawData["prompt"] = raw.Prompt
133→		}
134→
135→	case agent.HookPreToolUse, agent.HookPostToolUse:
136→		var raw toolHookInputRaw
137→		if err := json.Unmarshal(data, &raw); err != nil {
138→			return nil, fmt.Errorf("failed to parse tool hook input: %w", err)
139→		}
140→		input.SessionID = raw.SessionID
141→		input.SessionRef = raw.TranscriptPath
142→		input.ToolName = raw.ToolName
143→		input.ToolInput = raw.ToolInput
144→		if hookType == agent.HookPostToolUse {
145→			input.ToolResponse = raw.ToolResponse
146→		}
147→		input.RawData["cwd"] = raw.Cwd
148→		input.RawData["hook_event_name"] = raw.HookEventName
149→	}
150→
151→	return input, nil
152→}
