188→	// Check for test environment override
189→	if override := os.Getenv("ENTIRE_TEST_GEMINI_PROJECT_DIR"); override != "" {
190→		return override, nil
191→	}
192→
193→	homeDir, err := os.UserHomeDir()
194→	if err != nil {
195→		return "", fmt.Errorf("failed to get home directory: %w", err)
196→	}
197→
198→	// Gemini uses a hash of the project path for the directory name
199→	projectDir := SanitizePathForGemini(repoPath)
200→	return filepath.Join(homeDir, ".gemini", "tmp", projectDir, "chats"), nil
