 23→// EventPayload represents the data passed to the detached subprocess.
 24→// Note: APIKey and Endpoint are intentionally excluded to avoid exposing
 25→// them in process listings (ps/top). SendEvent reads them from package-level vars.
 26→type EventPayload struct {
 27→	Event      string         `json:"event"`
 28→	DistinctID string         `json:"distinct_id"`
 29→	Properties map[string]any `json:"properties"`
 30→	Timestamp  time.Time      `json:"timestamp"`
 31→}
 32→
 33→// silentLogger suppresses PostHog log output - expected for CLI best-effort telemetry
 34→type silentLogger struct{}
 35→
 36→func (silentLogger) Logf(_ string, _ ...interface{})   {}
 37→func (silentLogger) Debugf(_ string, _ ...interface{}) {}
 38→func (silentLogger) Warnf(_ string, _ ...interface{})  {}
 39→func (silentLogger) Errorf(_ string, _ ...interface{}) {}
 40→
 41→// BuildEventPayload constructs the event payload for tracking.
 42→// Exported for testing. Returns nil if the payload cannot be built.
 43→func BuildEventPayload(cmd *cobra.Command, strategy, agent string, isEntireEnabled bool, version string) *EventPayload {
 44→	if cmd == nil {
 45→		return nil
 46→	}
 47→
 48→	// Get machine ID for distinct_id
 49→	machineID, err := machineid.ProtectedID("entire-cli")
 50→	if err != nil {
 51→		return nil
 52→	}
 53→
 54→	// Collect flag names (not values) for privacy
 55→	var flags []string
 56→	cmd.Flags().Visit(func(flag *pflag.Flag) {
 57→		flags = append(flags, flag.Name)
 58→	})
 59→
 60→	selectedAgent := agent
 61→	if selectedAgent == "" {
 62→		selectedAgent = "auto"
 63→	}
 64→
 65→	properties := map[string]any{
 66→		"command":         cmd.CommandPath(),
 67→		"strategy":        strategy,
 68→		"agent":           selectedAgent,
 69→		"isEntireEnabled": isEntireEnabled,
 70→		"cli_version":     version,
 71→		"os":              runtime.GOOS,
 72→		"arch":            runtime.GOARCH,
 73→	}
 74→
 75→	if len(flags) > 0 {
 76→		properties["flags"] = strings.Join(flags, ",")
 77→	}
 78→
 79→	return &EventPayload{
 80→		Event:      "cli_command_executed",
 81→		DistinctID: machineID,
 82→		Properties: properties,
 83→		Timestamp:  time.Now(),
 84→	}
 85→}
