 87→// TrackCommandDetached tracks a command execution by spawning a detached subprocess.
 88→// This returns immediately without blocking the CLI.
 89→func TrackCommandDetached(cmd *cobra.Command, strategy, agent string, isEntireEnabled bool, version string) {
 90→	// Check opt-out environment variables
 91→	if os.Getenv("ENTIRE_TELEMETRY_OPTOUT") != "" {
 92→		return
 93→	}
 94→
 95→	if cmd == nil {
 96→		return
 97→	}
 98→
 99→	if cmd.Hidden {
100→		return
101→	}
102→
103→	payload := BuildEventPayload(cmd, strategy, agent, isEntireEnabled, version)
104→	if payload == nil {
105→		return
106→	}
107→
108→	if payloadJSON, err := json.Marshal(payload); err == nil {
109→		spawnDetachedAnalytics(string(payloadJSON))
110→	}
111→}
112→
113→// SendEvent processes an event payload in the detached subprocess.
114→// This is called by the hidden __send_analytics command.
115→func SendEvent(payloadJSON string) {
116→	var payload EventPayload
117→	if err := json.Unmarshal([]byte(payloadJSON), &payload); err != nil {
118→		return
119→	}
120→
121→	// Create PostHog client - no need for fast timeouts since we're detached
122→	// Read API key and endpoint from package-level vars (not passed via argv for security)
123→	client, err := posthog.NewWithConfig(PostHogAPIKey, posthog.Config{
124→		Endpoint:     PostHogEndpoint,
125→		Logger:       silentLogger{},
126→		DisableGeoIP: posthog.Ptr(true),
127→	})
128→	if err != nil {
129→		return
130→	}
131→	defer func() {
132→		_ = client.Close()
133→	}()
134→
135→	// Build properties
136→	props := posthog.NewProperties()
137→	for k, v := range payload.Properties {
138→		props.Set(k, v)
139→	}
140→
141→	//nolint:errcheck // Best effort telemetry - don't block on result
142→	_ = client.Enqueue(posthog.Capture{
143→		DistinctId: payload.DistinctID,
144→		Event:      payload.Event,
145→		Properties: props,
146→		Timestamp:  payload.Timestamp,
147→	})
148→}
