 516→// detectOrSelectAgent tries to auto-detect agents, or prompts the user to select.
 517→// Returns the detected/selected agents and any error.
 518→// When exactly one agent is detected, it is used automatically.
 519→// When multiple agents are detected, the user is prompted to confirm.
 520→// If no agent is detected and no TTY is available, falls back to the default agent.
 521→func detectOrSelectAgent(w io.Writer) ([]agent.Agent, error) {
 522→	// Try auto-detection first
 523→	detected := agent.DetectAll()
 524→
 525→	switch {
 526→	case len(detected) == 1:
 527→		// Single agent detected — use it directly
 528→		fmt.Fprintf(w, "Detected agent: %s\n\n", detected[0].Type())
 529→		return detected, nil
 530→
 531→	case len(detected) > 1:
 532→		// Multiple agents detected — prompt the user to confirm which to enable
 533→		agentTypes := make([]string, 0, len(detected))
 534→		for _, ag := range detected {
 535→			agentTypes = append(agentTypes, string(ag.Type()))
 536→		}
 537→		fmt.Fprintf(w, "Detected multiple agents: %s\n", strings.Join(agentTypes, ", "))
 538→		fmt.Fprintln(w)
 539→		// Fall through to the interactive multi-select below
 540→	}
 541→
 542→	// No agent detected (or multiple detected) — check if we can prompt interactively
 543→	if !canPromptInteractively() {
 544→		if len(detected) > 0 {
 545→			// Multiple agents detected but no TTY — use all of them
 546→			return detected, nil
 547→		}
 548→		// No TTY available (e.g., running in CI or tests) - fall back to default agent
 549→		defaultAgent := agent.Default()
 550→		if defaultAgent == nil {
 551→			return nil, errors.New("no default agent available")
 552→		}
 553→		fmt.Fprintf(w, "Agent: %s (use --agent to change)\n\n", defaultAgent.Type())
 554→		return []agent.Agent{defaultAgent}, nil
 555→	}
 556→
 557→	if len(detected) == 0 {
 558→		// Show message only when nothing was detected
 559→		fmt.Fprintln(w, "No agent configuration detected (e.g., .claude or .gemini directory).")
 560→		fmt.Fprintln(w, "This is normal - some agents don't require a config directory.")
 561→		fmt.Fprintln(w)
 562→	}
 563→
 564→	// Build a set of detected agent names for pre-selection
 565→	detectedSet := make(map[agent.AgentName]struct{}, len(detected))
 566→	for _, ag := range detected {
 567→		detectedSet[ag.Name()] = struct{}{}
 568→	}
 569→
 570→	// Build options from registered agents
 571→	agentNames := agent.List()
 572→	options := make([]huh.Option[string], 0, len(agentNames))
 573→	for _, name := range agentNames {
 574→		ag, err := agent.Get(name)
 575→		if err != nil {
 576→			continue
 577→		}
 578→		// Only show agents that support hooks
 579→		if _, ok := ag.(agent.HookSupport); !ok {
 580→			continue
 581→		}
 582→		label := string(ag.Type())
 583→		if name == agent.DefaultAgentName {
 584→			label += " (default)"
 585→		}
 586→		opt := huh.NewOption(label, string(name))
 587→		if _, isDetected := detectedSet[name]; isDetected {
 588→			opt = opt.Selected(true)
 589→		}
 590→		options = append(options, opt)
 591→	}
 592→
 593→	if len(options) == 0 {
 594→		return nil, errors.New("no agents with hook support available")
 595→	}
 596→
 597→	var selectedAgentNames []string
 598→	form := NewAccessibleForm(
 599→		huh.NewGroup(
 600→			huh.NewMultiSelect[string]().
 601→				Title("Which agents are you using?").
 602→				Description("Use space to select, enter to confirm.").
 603→				Options(options...).
 604→				Value(&selectedAgentNames),
 605→		),
 606→	)
 607→
 608→	if err := form.Run(); err != nil {
 609→		return nil, fmt.Errorf("agent selection cancelled: %w", err)
 610→	}
 611→
 612→	if len(selectedAgentNames) == 0 {
 613→		return nil, errors.New("no agents selected")
 614→	}
 615→
 616→	selectedAgents := make([]agent.Agent, 0, len(selectedAgentNames))
 617→	for _, name := range selectedAgentNames {
 618→		selectedAgent, err := agent.Get(agent.AgentName(name))
 619→		if err != nil {
 620→			return nil, fmt.Errorf("failed to get selected agent %s: %w", name, err)
 621→		}
 622→		selectedAgents = append(selectedAgents, selectedAgent)
 623→	}
 624→
 625→	agentTypes := make([]string, 0, len(selectedAgents))
 626→	for _, ag := range selectedAgents {
 627→		agentTypes = append(agentTypes, string(ag.Type()))
 628→	}
 629→	fmt.Fprintf(w, "\nSelected agents: %s\n\n", strings.Join(agentTypes, ", "))
 630→	return selectedAgents, nil
 631→}
