 676→// setupAgentHooksNonInteractive sets up hooks for a specific agent non-interactively.
 677→// If strategyName is provided, it sets the strategy; otherwise uses default.
 678→func setupAgentHooksNonInteractive(w io.Writer, ag agent.Agent, strategyName string, localDev, forceHooks, skipPushSessions, telemetry bool) error {
 679→	agentName := ag.Name()
 680→	// Check if agent supports hooks
 681→	hookAgent, ok := ag.(agent.HookSupport)
 682→	if !ok {
 683→		return fmt.Errorf("agent %s does not support hooks", agentName)
 684→	}
 685→
 686→	fmt.Fprintf(w, "Agent: %s\n\n", ag.Type())
 687→
 688→	// Install agent hooks (agent hooks don't depend on settings)
 689→	installedHooks, err := hookAgent.InstallHooks(localDev, forceHooks)
 690→	if err != nil {
 691→		return fmt.Errorf("failed to install hooks for %s: %w", agentName, err)
 692→	}
 693→
 694→	// Setup .entire directory
 695→	if _, err := setupEntireDirectory(); err != nil {
 696→		return fmt.Errorf("failed to setup .entire directory: %w", err)
 697→	}
 698→
 699→	// Load existing settings to preserve other options (like strategy_options.push)
 700→	settings, err := LoadEntireSettings()
 701→	if err != nil {
 702→		// If we can't load, start with defaults
 703→		settings = &EntireSettings{Strategy: strategy.DefaultStrategyName}
 704→	}
 705→	settings.Enabled = true
 706→	if localDev {
 707→		settings.LocalDev = localDev
 708→	}
 709→
 710→	// Set push_sessions option if --skip-push-sessions flag was provided
 711→	if skipPushSessions {
 712→		if settings.StrategyOptions == nil {
 713→			settings.StrategyOptions = make(map[string]interface{})
 714→		}
 715→		settings.StrategyOptions["push_sessions"] = false
 716→	}
 717→
 718→	// Set strategy if provided
 719→	if strategyName != "" {
 720→		// Map display name to internal name if needed
 721→		internalStrategy := strategyName
 722→		if mapped, ok := strategyDisplayToInternal[strategyName]; ok {
 723→			internalStrategy = mapped
 724→		}
 725→		// Validate the strategy exists
 726→		if _, err := strategy.Get(internalStrategy); err != nil {
 727→			return fmt.Errorf("unknown strategy: %s (use manual-commit or auto-commit)", strategyName)
 728→		}
 729→		settings.Strategy = internalStrategy
 730→	}
 731→
 732→	// Handle telemetry for non-interactive mode
 733→	// Note: if telemetry is nil (not configured), it defaults to disabled
 734→	if !telemetry || os.Getenv("ENTIRE_TELEMETRY_OPTOUT") != "" {
 735→		f := false
 736→		settings.Telemetry = &f
 737→	}
 738→
 739→	if err := SaveEntireSettings(settings); err != nil {
 740→		return fmt.Errorf("failed to save settings: %w", err)
 741→	}
 742→
 743→	// Install git hooks AFTER saving settings (InstallGitHook reads local_dev from settings)
 744→	if _, err := strategy.InstallGitHook(true); err != nil {
 745→		return fmt.Errorf("failed to install git hooks: %w", err)
 746→	}
 747→	strategy.CheckAndWarnHookManagers(w)
 748→
 749→	if installedHooks == 0 {
 750→		msg := fmt.Sprintf("Hooks for %s already installed", ag.Description())
 751→		if agentName == agent.AgentNameGemini {
 752→			msg += " (Preview)"
 753→		}
 754→		fmt.Fprintf(w, "%s\n", msg)
 755→	} else {
 756→		msg := fmt.Sprintf("Installed %d hooks for %s", installedHooks, ag.Description())
 757→		if agentName == agent.AgentNameGemini {
 758→			msg += " (Preview)"
 759→		}
 760→		fmt.Fprintf(w, "%s\n", msg)
 761→	}
 762→
 763→	fmt.Fprintf(w, "✓ Project configured (%s)\n", configDisplayProject)
 764→
 765→	// Let the strategy handle its own setup requirements (creates entire/checkpoints/v1 branch, etc.)
 766→	strat, err := strategy.Get(settings.Strategy)
 767→	if err != nil {
 768→		return fmt.Errorf("failed to get strategy: %w", err)
 769→	}
 770→	if err := strat.EnsureSetup(); err != nil {
 771→		return fmt.Errorf("failed to setup strategy: %w", err)
 772→	}
 773→
 774→	fmt.Fprintln(w, "\nReady.")
 775→
 776→	return nil
 777→}
