 883→// shellCompletionComment is the comment preceding the completion line
 884→const shellCompletionComment = "# Entire CLI shell completion"
 885→
 886→// errUnsupportedShell is returned when the user's shell is not supported for completion.
 887→var errUnsupportedShell = errors.New("unsupported shell")
 888→
 889→// shellCompletionTarget returns the rc file path and completion lines for the
 890→// user's current shell.
 891→func shellCompletionTarget() (shellName, rcFile, completionLine string, err error) {
 892→	home, err := os.UserHomeDir()
 893→	if err != nil {
 894→		return "", "", "", fmt.Errorf("cannot determine home directory: %w", err)
 895→	}
 896→
 897→	shell := os.Getenv("SHELL")
 898→	switch {
 899→	case strings.Contains(shell, "zsh"):
 900→		return "Zsh",
 901→			filepath.Join(home, ".zshrc"),
 902→			"autoload -Uz compinit && compinit && source <(entire completion zsh)",
 903→			nil
 904→	case strings.Contains(shell, "bash"):
 905→		bashRC := filepath.Join(home, ".bashrc")
 906→		if _, err := os.Stat(filepath.Join(home, ".bash_profile")); err == nil {
 907→			bashRC = filepath.Join(home, ".bash_profile")
 908→		}
 909→		return "Bash",
 910→			bashRC,
 911→			"source <(entire completion bash)",
 912→			nil
 913→	case strings.Contains(shell, "fish"):
 914→		return "Fish",
 915→			filepath.Join(home, ".config", "fish", "config.fish"),
 916→			"entire completion fish | source",
 917→			nil
 918→	default:
 919→		return "", "", "", errUnsupportedShell
 920→	}
 921→}
 922→
 923→// promptShellCompletion offers to add shell completion to the user's rc file.
 924→// Only prompts if completion is not already configured.
 925→func promptShellCompletion(w io.Writer) error {
 926→	shellName, rcFile, completionLine, err := shellCompletionTarget()
 927→	if err != nil {
 928→		if errors.Is(err, errUnsupportedShell) {
 929→			fmt.Fprintf(w, "Note: Shell completion not available for your shell. Supported: zsh, bash, fish.\n")
 930→			return nil
 931→		}
 932→		return fmt.Errorf("shell completion: %w", err)
 933→	}
 934→
 935→	if isCompletionConfigured(rcFile) {
 936→		fmt.Fprintf(w, "✓ Shell completion already configured in %s\n", rcFile)
 937→		return nil
 938→	}
 939→
 940→	var selected string
 941→	form := NewAccessibleForm(
 942→		huh.NewGroup(
 943→			huh.NewSelect[string]().
 944→				Title(fmt.Sprintf("Enable shell completion? (detected: %s)", shellName)).
 945→				Options(
 946→					huh.NewOption("Yes", "yes"),
 947→					huh.NewOption("No", "no"),
 948→				).
 949→				Value(&selected),
 950→		),
 951→	)
 952→
 953→	if err := form.Run(); err != nil {
 954→		//nolint:nilerr // User cancelled - not a fatal error, just skip
 955→		return nil
 956→	}
 957→
 958→	if selected != "yes" {
 959→		return nil
 960→	}
 961→
 962→	if err := appendShellCompletion(rcFile, completionLine); err != nil {
 963→		return fmt.Errorf("failed to update %s: %w", rcFile, err)
 964→	}
 965→
 966→	fmt.Fprintf(w, "✓ Shell completion added to %s\n", rcFile)
 967→	fmt.Fprintln(w, "  Restart your shell to activate")
 968→
 969→	return nil
 970→}
 971→
 972→// isCompletionConfigured checks if shell completion is already in the rc file.
 973→func isCompletionConfigured(rcFile string) bool {
 974→	//nolint:gosec // G304: rcFile is constructed from home dir + known filename, not user input
 975→	content, err := os.ReadFile(rcFile)
 976→	if err != nil {
 977→		return false // File doesn't exist or can't read, treat as not configured
 978→	}
 979→	return strings.Contains(string(content), "entire completion")
 980→}
 981→
 982→// appendShellCompletion adds the completion line to the rc file.
 983→func appendShellCompletion(rcFile, completionLine string) error {
 984→	if err := os.MkdirAll(filepath.Dir(rcFile), 0o700); err != nil {
 985→		return fmt.Errorf("creating directory: %w", err)
 986→	}
 987→	//nolint:gosec // G302: Shell rc files need 0644 for user readability
 988→	f, err := os.OpenFile(rcFile, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
 989→	if err != nil {
 990→		return fmt.Errorf("opening file: %w", err)
 991→	}
 992→	defer f.Close()
 993→
 994→	_, err = f.WriteString("\n" + shellCompletionComment + "\n" + completionLine + "\n")
 995→	if err != nil {
 996→		return fmt.Errorf("writing completion: %w", err)
 997→	}
 998→	return nil
 999→}
