1044→// runUninstall completely removes Entire from the repository.
1045→func runUninstall(w, errW io.Writer, force bool) error {
1046→	// Check if we're in a git repository
1047→	if _, err := paths.RepoRoot(); err != nil {
1048→		fmt.Fprintln(errW, "Not a git repository. Nothing to uninstall.")
1049→		return NewSilentError(errors.New("not a git repository"))
1050→	}
1051→
1052→	// Gather counts for display
1053→	sessionStateCount := countSessionStates()
1054→	shadowBranchCount := countShadowBranches()
1055→	gitHooksInstalled := strategy.IsGitHookInstalled()
1056→	claudeHooksInstalled := checkClaudeCodeHooksInstalled()
1057→	geminiHooksInstalled := checkGeminiCLIHooksInstalled()
1058→	entireDirExists := checkEntireDirExists()
1059→
1060→	// Check if there's anything to uninstall
1061→	if !entireDirExists && !gitHooksInstalled && sessionStateCount == 0 &&
1062→		shadowBranchCount == 0 && !claudeHooksInstalled && !geminiHooksInstalled {
1063→		fmt.Fprintln(w, "Entire is not installed in this repository.")
1064→		return nil
1065→	}
1066→
1067→	// Show confirmation prompt unless --force
1068→	if !force {
1069→		fmt.Fprintln(w, "\nThis will completely remove Entire from this repository:")
1070→		if entireDirExists {
1071→			fmt.Fprintln(w, "  - .entire/ directory")
1072→		}
1073→		if gitHooksInstalled {
1074→			fmt.Fprintln(w, "  - Git hooks (prepare-commit-msg, commit-msg, post-commit, pre-push)")
1075→		}
1076→		if sessionStateCount > 0 {
1077→			fmt.Fprintf(w, "  - Session state files (%d)\n", sessionStateCount)
1078→		}
1079→		if shadowBranchCount > 0 {
1080→			fmt.Fprintf(w, "  - Shadow branches (%d)\n", shadowBranchCount)
1081→		}
1082→		switch {
1083→		case claudeHooksInstalled && geminiHooksInstalled:
1084→			fmt.Fprintln(w, "  - Agent hooks (Claude Code, Gemini CLI)")
1085→		case claudeHooksInstalled:
1086→			fmt.Fprintln(w, "  - Agent hooks (Claude Code)")
1087→		case geminiHooksInstalled:
1088→			fmt.Fprintln(w, "  - Agent hooks (Gemini CLI)")
1089→		}
1090→		fmt.Fprintln(w)
1091→
1092→		var confirmed bool
1093→		form := NewAccessibleForm(
1094→			huh.NewGroup(
