 696→func TestAppendShellCompletion(t *testing.T) {
 697→	tests := []struct {
 698→		name           string
 699→		rcFileRelPath  string
 700→		completionLine string
 701→		preExisting    string // existing content in rc file; empty means file doesn't exist
 702→		createParent   bool   // whether parent dir already exists
 703→	}{
 704→		{
 705→			name:           "zsh_new_file",
 706→			rcFileRelPath:  ".zshrc",
 707→			completionLine: "source <(entire completion zsh)",
 708→			createParent:   true,
 709→		},
 710→		{
 711→			name:           "zsh_existing_file",
 712→			rcFileRelPath:  ".zshrc",
 713→			completionLine: "source <(entire completion zsh)",
 714→			preExisting:    "# existing zshrc content\n",
 715→			createParent:   true,
 716→		},
 717→		{
 718→			name:           "fish_no_parent_dir",
 719→			rcFileRelPath:  filepath.Join(".config", "fish", "config.fish"),
 720→			completionLine: "entire completion fish | source",
 721→			createParent:   false,
 722→		},
 723→		{
 724→			name:           "fish_existing_dir",
 725→			rcFileRelPath:  filepath.Join(".config", "fish", "config.fish"),
 726→			completionLine: "entire completion fish | source",
 727→			createParent:   true,
 728→		},
 729→	}
 730→
 731→	for _, tt := range tests {
 732→		t.Run(tt.name, func(t *testing.T) {
 733→			home := t.TempDir()
 734→			rcFile := filepath.Join(home, tt.rcFileRelPath)
 735→
 736→			if tt.createParent {
 737→				if err := os.MkdirAll(filepath.Dir(rcFile), 0o755); err != nil {
 738→					t.Fatal(err)
 739→				}
 740→			}
 741→			if tt.preExisting != "" {
 742→				if err := os.WriteFile(rcFile, []byte(tt.preExisting), 0o644); err != nil {
 743→					t.Fatal(err)
 744→				}
 745→			}
 746→
 747→			if err := appendShellCompletion(rcFile, tt.completionLine); err != nil {
 748→				t.Fatalf("appendShellCompletion() error: %v", err)
 749→			}
 750→
 751→			// Verify the file was created and contains the completion line.
 752→			data, err := os.ReadFile(rcFile)
 753→			if err != nil {
 754→				t.Fatalf("reading rc file: %v", err)
 755→			}
 756→			content := string(data)
 757→
 758→			if !strings.Contains(content, shellCompletionComment) {
 759→				t.Errorf("rc file missing comment %q", shellCompletionComment)
 760→			}
 761→			if !strings.Contains(content, tt.completionLine) {
 762→				t.Errorf("rc file missing completion line %q", tt.completionLine)
 763→			}
 764→			if tt.preExisting != "" && !strings.HasPrefix(content, tt.preExisting) {
 765→				t.Errorf("pre-existing content was overwritten")
 766→			}
 767→
 768→			// Verify parent directory permissions.
 769→			info, err := os.Stat(filepath.Dir(rcFile))
 770→			if err != nil {
 771→				t.Fatalf("stat parent dir: %v", err)
 772→			}
 773→			if !info.IsDir() {
 774→				t.Fatal("parent path is not a directory")
 775→			}
 776→		})
 777→	}
